/*
 * Precision Agriculture - Soil Moisture Sensor Node
 * Arduino Nano with LoRa SX1278 Module
 * Transmits sensor data to gateway every 60 seconds
 */

#include <SPI.h>
#include <LoRa.h>

// Pin Definitions
#define SOIL_MOISTURE_PIN A0    // Analog input for soil moisture sensor
#define TEMP_HUMIDITY_PIN 2     # Digital pin for DHT22 sensor
#define LED_STATUS 13           // Built-in LED for status indication
#define BATTERY_PIN A1          // Battery voltage monitoring

// Node Configuration
#define NODE_ID "NODE01"
#define TX_INTERVAL 60000       // Transmission interval in milliseconds (1 minute)

// LoRa Configuration (915 MHz for US/Australia, adjust for your region)
#define LORA_FREQ 915E6
#define LORA_SF 7               # Spreading factor (higher = more range, slower)
#define LORA_BW 125E3           # Bandwidth
#define LORA_CR 5               # Coding rate
#define LORA_SYNC_WORD 0x34     # Private network sync word

// Thresholds
#define MOISTURE_LOW_THRESHOLD 30
#define MOISTURE_HIGH_THRESHOLD 70

// Global variables
unsigned long lastTxTime = 0;
int packetCounter = 0;

// Structure to hold sensor data
struct SensorData {
    char nodeId[10];
    int moisture;       // 0-100 percentage
    int temperature;   // Celsius
    int humidity;      // Percentage
    int battery;       // Percentage
    int rssi;          // Signal strength
};

// Simple DHT22 reading (without library for demonstration)
int readDHT22(int *temperature, int *humidity) {
    // In real implementation, use DHT library:
    // #include <DHT.h>
    // DHT dht(TEMP_HUMIDITY_PIN, DHT22);
    // *temperature = dht.readTemperature();
    // *humidity = dht.readHumidity();

    // Simulation for demo purposes
    *temperature = 25 + random(10);
    *humidity = 50 + random(30);
    return 0;
}

// Read soil moisture sensor
int readSoilMoisture() {
    int rawValue = analogRead(SOIL_MOISTURE_PIN);
    // Map analog value (0-1023) to percentage
    // Dry soil = high resistance = low analog value
    // Wet soil = low resistance = high analog value
    int moisturePercent = map(rawValue, 0, 1023, 0, 100);
    return moisturePercent;
}

// Read battery voltage and convert to percentage
int readBatteryLevel() {
    int rawBattery = analogRead(BATTERY_PIN);
    float voltage = (rawBattery / 1023.0) * 4.2;  // Assuming 4.2V max (LiPo)
    int percentage = (voltage / 4.2) * 100;
    return constrain(percentage, 0, 100);
}

// Initialize LoRa module
bool initLoRa() {
    Serial.println("Initializing LoRa...");

    // LoRa chip select pin and interrupt pin
    if (!LoRa.begin(LORA_FREQ)) {
        Serial.println("LoRa init failed!");
        return false;
    }

    // Configure LoRa parameters
    LoRa.setSpreadingFactor(LORA_SF);
    LoRa.setSignalBandwidth(LORA_BW);
    LoRa.setCodingRate4(LORA_CR);
    LoRa.setSyncWord(LORA_SYNC_WORD);
    LoRa.enableCrc();

    Serial.println("LoRa initialized successfully");
    return true;
}

// Transmit sensor data packet
void transmitData(SensorData *data) {
    Serial.println("Transmitting data...");

    // Create JSON-like payload
    String payload = String(data->nodeId) + "," +
                     String(data->moisture) + "," +
                     String(data->temperature) + "," +
                     String(data->humidity);

    // Send packet
    LoRa.beginPacket();
    LoRa.print(payload);
    LoRa.endPacket(true);  // True = async, non-blocking

    // Get RSSI after transmission
    data->rssi = LoRa.rssi();

    // Flash LED to indicate transmission
    digitalWrite(LED_STATUS, HIGH);
    delay(100);
    digitalWrite(LED_STATUS, LOW);

    Serial.print("Transmitted - Moisture: ");
    Serial.print(data->moisture);
    Serial.print("%, Temp: ");
    Serial.print(data->temperature);
    Serial.print("°C, RSSI: ");
    Serial.println(data->rssi);

    packetCounter++;
}

// Put Arduino to sleep for power conservation
void goToSleep(unsigned long durationMs) {
    Serial.println("Entering sleep mode...");
    delay(100);

    // Use LowPower library in production:
    // LowPower.sleep(durationMs);

    // Simple delay for demo (replace with actual sleep in production)
    delay(durationMs);
}

void setup() {
    // Initialize serial communication
    Serial.begin(9600);
    while (!Serial && millis() < 5000);

    Serial.println("===========================");
    Serial.println("Soil Moisture Sensor Node");
    Serial.println("===========================");

    // Configure pins
    pinMode(SOIL_MOISTURE_PIN, INPUT);
    pinMode(BATTERY_PIN, INPUT);
    pinMode(LED_STATUS, OUTPUT);

    // Initialize LoRa
    if (!initLoRa()) {
        Serial.println("LoRa initialization failed - continuing anyway");
    }

    // Initialize random seed
    randomSeed(analogRead(0));

    Serial.println("Setup complete");
    Serial.print("Node ID: ");
    Serial.println(NODE_ID);
    Serial.print("TX Interval: ");
    Serial.print(TX_INTERVAL / 1000);
    Serial.println(" seconds");
}

void loop() {
    unsigned long currentTime = millis();

    // Check if it's time to transmit
    if (currentTime - lastTxTime >= TX_INTERVAL) {
        // Create sensor data structure
        SensorData sensorData;

        // Copy node ID
        strcpy(sensorData.nodeId, NODE_ID);

        // Read sensors
        sensorData.moisture = readSoilMoisture();
        readDHT22(&sensorData.temperature, &sensorData.humidity);
        sensorData.battery = readBatteryLevel();

        // Debug output
        Serial.println("\n=== Sensor Readings ===");
        Serial.print("Moisture: ");
        Serial.print(sensorData.moisture);
        Serial.println("%");
        Serial.print("Temperature: ");
        Serial.print(sensorData.temperature);
        Serial.println("°C");
        Serial.print("Humidity: ");
        Serial.print(sensorData.humidity);
        Serial.println("%");
        Serial.print("Battery: ");
        Serial.print(sensorData.battery);
        Serial.println("%");

        // Check for critical conditions
        if (sensorData.moisture < MOISTURE_LOW_THRESHOLD) {
            Serial.println("ALERT: Low soil moisture!");
        }

        if (sensorData.battery < 20) {
            Serial.println("ALERT: Low battery!");
        }

        // Transmit data
        transmitData(&sensorData);

        // Update last transmission time
        lastTxTime = currentTime;
    }

    // Sleep to conserve power between transmissions
    // In production, use deep sleep: ESP32.deepSleep(TX_INTERVAL * 1000);
    delay(1000);
}
